class ArrayManipulator {
    // Method to rearrange array by alternating signs
    rearrangeBySign(A, n) {
        let pos = []; // Array for positive numbers
        let neg = []; // Array for negative numbers

        // Step 1: Separate positives and negatives
        for (let i = 0; i < n; i++) {
            if (A[i] > 0) {
                pos.push(A[i]);
            } else {
                neg.push(A[i]);
            }
        }

        // Step 2: Fill even indices with positives, odd with negatives
        for (let i = 0; i < Math.floor(n / 2); i++) {
            A[2 * i] = pos[i];      // Even index → positive
            A[2 * i + 1] = neg[i];  // Odd index → negative
        }

        return A;
    }
}

